            }
        }
        
        log.LogInformation($"[{correlationId}] Client IP: {req.HttpContext.Connection.RemoteIpAddress}");
        log.LogInformation($"[{correlationId}] Request Method: {req.Method}");
        log.LogInformation($"[{correlationId}] Request Path: {req.Path}");
        log.LogInformation($"[{correlationId}] Request Scheme: {req.Scheme}");
        log.LogInformation($"[{correlationId}] Request Host: {req.Host}");
