                string query = @"
                    SELECT UserId, UserName, Email, LastLoginDate, AccountBalance, CreditCardNumber, SSN
                    FROM Users 
                    WHERE UserId = @UserId";
                
                log.LogInformation($"[{correlationId}] Executing Query: {query}");
                
                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    command.Parameters.AddWithValue("@UserId", userId);
                    
                    log.LogInformation($"[{correlationId}] === QUERY PARAMETERS ===");
                    foreach (SqlParameter param in command.Parameters)
