    private static void LogFullException(Exception ex, ILogger log, string correlationId)
    {
        log.LogError($"[{correlationId}] === EXCEPTION DETAILS ===");
        log.LogError($"[{correlationId}] Exception Type: {ex.GetType().FullName}");
        log.LogError($"[{correlationId}] Exception Message: {ex.Message}");
        log.LogError($"[{correlationId}] Exception Source: {ex.Source}");
        log.LogError($"[{correlationId}] Exception HelpLink: {ex.HelpLink}");
        log.LogError($"[{correlationId}] Exception HResult: {ex.HResult}");
        log.LogError($"[{correlationId}] Exception TargetSite: {ex.TargetSite}");
        
        log.LogError($"[{correlationId}] === STACK TRACE ===");
        log.LogError($"[{correlationId}] {ex.StackTrace}");
        
        if (ex.Data.Count > 0)
        {
            log.LogError($"[{correlationId}] === EXCEPTION DATA ===");
            foreach (var key in ex.Data.Keys)
            {
                log.LogError($"[{correlationId}] Data: {key} = {ex.Data[key]}");
            }
        }
        
        if (ex.InnerException != null)
        {
            log.LogError($"[{correlationId}] === INNER EXCEPTION ===");
            LogInnerException(ex.InnerException, log, correlationId, 1);
        }
        
        log.LogError($"[{correlationId}] === COMPLETE EXCEPTION OBJECT ===");
        log.LogError($"[{correlationId}] {ex.ToString()}");
    }
    
    private static void LogInnerException(Exception ex, ILogger log, string correlationId, int level)
    {
        log.LogError($"[{correlationId}] Inner Exception Level {level}:");
        log.LogError($"[{correlationId}] Type: {ex.GetType().FullName}");
        log.LogError($"[{correlationId}] Message: {ex.Message}");
        log.LogError($"[{correlationId}] Stack Trace: {ex.StackTrace}");
        
        if (ex.InnerException != null)
        {
            LogInnerException(ex.InnerException, log, correlationId, level + 1);
        }
    }
